        expect(document.activeElement).toBe(items[0]);
      });

      it('ArrowUp wraps from the first menuitem back to the last', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const menu = menuOf(actions);
        const items = menuItemsOf(menu);
        menuBtnOf(actions).click();
        expect(document.activeElement).toBe(items[0]); // first is focused on open

        pressKey(menu, 'ArrowUp');
        expect(document.activeElement).toBe(items[items.length - 1]);
      });

      it('ArrowDown and ArrowUp call preventDefault (no page scroll)', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const menu = menuOf(actions);
        menuBtnOf(actions).click();

        expect(pressKey(menu, 'ArrowDown').defaultPrevented).toBe(true);
        expect(pressKey(menu, 'ArrowUp').defaultPrevented).toBe(true);
      });

      /* ---- Escape closes the menu and returns focus to the trigger ------- */
      it('Escape on the menu closes it and returns focus to the ⚡ trigger button', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const btn = menuBtnOf(actions);
        const menu = menuOf(actions);
        btn.click();
        expect(menu.hidden).toBe(false);

        pressKey(menu, 'Escape');

        expect(menu.hidden).toBe(true);
        expect(btn.getAttribute('aria-expanded')).toBe('false');
        expect(document.activeElement).toBe(btn);
      });
    });
  });
});

