111: * Build the per-row "⋮" action menu for a browse data row: a `.row-menu-btn`
143:  btn.className = 'row-menu-btn';

     *
     * These pin the accessibility fix that completes the previously partial
     * menu pattern (the trigger previously carried only aria-haspopup /
     * aria-expanded). Each test is independent and reuses the row action menu
     * `beforeEach` Escape cleanup so no menu is left open between tests.
     * ===================================================================== */
    describe('ARIA menu pattern & keyboard navigation', () => {
      function menuItemsOf(menu: Element): HTMLElement[] {
        return Array.from(menu.querySelectorAll('[role=menuitem]')) as HTMLElement[];
      }

      /** Dispatch a `keydown` on `target`; return the event for assertions. */
      function pressKey(target: Element, key: string): KeyboardEvent {
        const evt = new KeyboardEvent('keydown', { key, bubbles: true, cancelable: true });
        target.dispatchEvent(evt);
        return evt;
      }

      /* ---- aria-controls + stable menu id -------------------------------- */
      it('gives the .row-menu a non-empty stable id', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const menu = menuOf(actionsOf(results, 'a.txt'));
        expect(typeof menu.id).toBe('string');
        expect(menu.id.length).toBeGreaterThan(0);
      });

      it('sets aria-controls on the ⚡ button to the menu id so AT can pair them', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const btn = menuBtnOf(actions);
        const menu = menuOf(actions);
        const controls = btn.getAttribute('aria-controls');
        expect(controls).not.toBeNull();
        expect(controls).toBe(menu.id);
        // The referenced id actually resolves to THIS menu element.
        expect(document.getElementById(controls!)).toBe(menu);
      });

      it('gives each row menu a distinct id (unique per row)', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file, dir] }));

        const idA = menuOf(actionsOf(results, 'a.txt')).id;
        const idB = menuOf(actionsOf(results, 'sub')).id;
        expect(idA).not.toBe('');
        expect(idB).not.toBe('');
        expect(idA).not.toBe(idB);
      });

      /* ---- role=menu / role=menuitem ------------------------------------- */
      it('tags the .row-menu container with role="menu"', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file, dir] }));

        for (const name of ['a.txt', 'sub']) {
          expect(menuOf(actionsOf(results, name)).getAttribute('role')).toBe('menu');
        }
      });

      it('tags every action element with role="menuitem" for files (Download+Delete+Move+Copy)', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const menu = menuOf(actionsOf(results, 'a.txt'));
        const children = Array.from(menu.children) as HTMLElement[];
        expect(children).toHaveLength(4); // Download, Delete, Move, Copy
        for (const item of children) {
          expect(item.getAttribute('role')).toBe('menuitem');
        }
        expect(menuItemsOf(menu)).toHaveLength(4);
      });

      it('tags every action element with role="menuitem" for folders (Delete+Move+Copy)', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

        const menu = menuOf(actionsOf(results, 'sub'));
        const children = Array.from(menu.children) as HTMLElement[];
        expect(children).toHaveLength(3);
        for (const item of children) {
          expect(item.getAttribute('role')).toBe('menuitem');
        }
        expect(menuItemsOf(menu)).toHaveLength(3);
      });

      /* ---- focus management on open -------------------------------------- */
      it('moves focus to the first menuitem when the menu opens via the ⚡ button', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const menu = menuOf(actions);
        const items = menuItemsOf(menu);
        expect(items.length).toBeGreaterThan(0);

        menuBtnOf(actions).click();

        expect(menu.hidden).toBe(false);
        expect(document.activeElement).toBe(items[0]);
      });

      it('moves focus to the first menuitem when the menu opens via right-click', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const row = rowByName(results.querySelector('table')!, 'a.txt')!;
        const menu = menuOf(actionsOf(results, 'a.txt'));
        const items = menuItemsOf(menu);

        row.dispatchEvent(
          new MouseEvent('contextmenu', {
            cancelable: true,
            bubbles: true,
            clientX: 5,
            clientY: 6,
          }),
        );

        expect(menu.hidden).toBe(false);
        expect(document.activeElement).toBe(items[0]);
      });

      /* ---- arrow-key navigation (with wrap-around) ----------------------- */
      it('ArrowDown moves focus to the next menuitem', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const menu = menuOf(actions);
        const items = menuItemsOf(menu);
        menuBtnOf(actions).click();
        expect(document.activeElement).toBe(items[0]);

        pressKey(menu, 'ArrowDown');
        expect(document.activeElement).toBe(items[1]);

        pressKey(menu, 'ArrowDown');
        expect(document.activeElement).toBe(items[2]);
      });

      it('ArrowDown wraps from the last menuitem back to the first', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const menu = menuOf(actions);
        const items = menuItemsOf(menu);
        menuBtnOf(actions).click();
        expect(items.length).toBeGreaterThan(0); // role=menuitem must exist to navigate
        const last = items[items.length - 1];
        last.focus(); // place focus on the last item, as if the user navigated there
        expect(document.activeElement).toBe(last);

        pressKey(menu, 'ArrowDown');
        expect(document.activeElement).toBe(items[0]);
      });

      it('ArrowUp moves focus to the previous menuitem', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const menu = menuOf(actions);
        const items = menuItemsOf(menu);
        menuBtnOf(actions).click();
        // Advance one item first.
        pressKey(menu, 'ArrowDown');
        expect(document.activeElement).toBe(items[1]);

        pressKey(menu, 'ArrowUp');
        expect(document.activeElement).toBe(items[0]);
      });

      it('ArrowUp wraps from the first menuitem back to the last', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const menu = menuOf(actions);
        const items = menuItemsOf(menu);
        menuBtnOf(actions).click();
        expect(document.activeElement).toBe(items[0]); // first is focused on open

        pressKey(menu, 'ArrowUp');
        expect(document.activeElement).toBe(items[items.length - 1]);
      });

      it('ArrowDown and ArrowUp call preventDefault (no page scroll)', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const menu = menuOf(actions);
        menuBtnOf(actions).click();

        expect(pressKey(menu, 'ArrowDown').defaultPrevented).toBe(true);
        expect(pressKey(menu, 'ArrowUp').defaultPrevented).toBe(true);
      });

      /* ---- Escape closes the menu and returns focus to the trigger ------- */
      it('Escape on the menu closes it and returns focus to the ⚡ trigger button', async () => {
        const { results } = await setupCleared();
        renderBrowse(browseResult({ path: 'docs', entries: [file] }));

        const actions = actionsOf(results, 'a.txt');
        const btn = menuBtnOf(actions);
        const menu = menuOf(actions);
        btn.click();
        expect(menu.hidden).toBe(false);

        pressKey(menu, 'Escape');

        expect(menu.hidden).toBe(true);
        expect(btn.getAttribute('aria-expanded')).toBe('false');
        expect(document.activeElement).toBe(btn);
      });
    });
  });
});

function makeRowMenu(entry: FileEntry): {
  btn: HTMLButtonElement;
  menu: HTMLElement;
  openMenu: (x: number, y: number) => void;
} {
  const btn = document.createElement('button');
  btn.className = 'row-menu-btn';
  btn.type = 'button';
  btn.setAttribute('aria-label', 'Actions');
  btn.setAttribute('aria-haspopup', 'true');
  btn.setAttribute('aria-expanded', 'false');
  btn.textContent = '⋮';

  const menu = document.createElement('div');
  menu.className = 'row-menu';
  menu.hidden = true;

  // Menu items — same handlers/attributes as the former inline controls.
  if (!entry.isDirectory) {
    const download = document.createElement('a');
    download.className = 'btn';
    download.setAttribute('href', getApi().downloadUrl(entry.path));
    download.setAttribute('download', entry.name);
    download.textContent = 'Download';
    menu.append(download);
  }
  menu.append(
    makeActionButton('Delete', async () => {
      if (!window.confirm('Delete "' + entry.name + '"?')) {
        return;
      }
      await getApi().delete(entry.path);
      rerender();
    }),
  );
  menu.append(
    makeActionButton('Move', async () => {
      const dest = window.prompt('Move to relative destination path:', entry.path);
      if (dest === null) {
        return;
      }
      await getApi().move(entry.path, normalizeRelativePath(dest));
      rerender();
    }),
  );
  menu.append(
    makeActionButton('Copy', async () => {
      const dest = window.prompt('Copy to relative destination path:', entry.path);
      if (dest === null) {
        return;
      }
      await getApi().copy(entry.path, normalizeRelativePath(dest));
      rerender();
    }),
  );

  // Document listeners registered on open, removed on close. Kept as named
  // references so removeEventListener tears down the exact functions.
  function onDocClick(): void {
    closeMenu();
  }
  function onDocKey(event: KeyboardEvent): void {
    if (event.key === 'Escape') {
      closeMenu();
    }
  }
  // The menu is position:fixed at viewport coords, so it detaches from its
  // owning row on scroll/resize. Dismiss it instead of leaving it stranded
  // over (potentially) the wrong row. Capturing on 'scroll' so it also fires
  // for scrolls inside the .results overflow container, not just the window.
  function onScrollOrResize(): void {
    closeMenu();
  }

  function closeMenu(): void {
    menu.hidden = true;
    btn.setAttribute('aria-expanded', 'false');
    document.removeEventListener('click', onDocClick);
    document.removeEventListener('keydown', onDocKey);
    window.removeEventListener('scroll', onScrollOrResize, true);
    window.removeEventListener('resize', onScrollOrResize);
    if (openRowMenu?.close === closeMenu) {
      openRowMenu = null;
    }
  }

  function openMenu(x: number, y: number): void {
    closeAllRowMenus();
    menu.style.left = x + 'px';
    menu.style.top = y + 'px';
    menu.hidden = false;
    btn.setAttribute('aria-expanded', 'true');
    document.addEventListener('click', onDocClick);
    document.addEventListener('keydown', onDocKey);
    window.addEventListener('scroll', onScrollOrResize, true);
    window.addEventListener('resize', onScrollOrResize);
    openRowMenu = { close: closeMenu };
  }

  // Toggle: open below the button, or close if already open. stopPropagation on
  // the OPENING click is critical — without it the click would bubble to the
  // document listener registered by openMenu and close the menu immediately.
  btn.addEventListener('click', (event) => {
    if (menu.hidden) {
      event.stopPropagation();
      const rect = btn.getBoundingClientRect();
      openMenu(rect.left, rect.bottom);
    } else {
      closeMenu();
    }
  });

  return { btn, menu, openMenu };
}

/** One data row in the browse table (a file or folder entry). */
export function makeBrowseRow(entry: FileEntry): HTMLTableRowElement {
  const row = document.createElement('tr');

  // Name — directory names are navigation links; file names are plain text.
  const nameCell = document.createElement('td');
  if (entry.isDirectory) {
    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
  } else {
    nameCell.textContent = entry.name;
  }

  // Size — em-dash for folders, formatted bytes for files.
  const sizeCell = document.createElement('td');
  sizeCell.textContent = entry.isDirectory ? '—' : formatBytes(entry.size);

