1:/**
2: * Pure DOM-construction helpers for the file-browser tables, breadcrumb, and
3: * action controls.
4: *
5: * Every function here builds and returns a DOM subtree (or, for
6: * `renderBreadcrumb`, populates the shared breadcrumb element from the
7: * context). They hold no state of their own; the shared element refs and API
8: * client are read from `./context.js`.
9: *
10: * All user-controlled strings (file/folder names, paths) are inserted via
11: * `textContent` / element creation — never via `innerHTML` — to prevent HTML
12: * injection.
13: */
14:import type { FileEntry } from '../api.js';
15:import { formatBytes, formatDate, joinPath, normalizeRelativePath } from '../format.js';
16:import { navigate, toBrowseHash } from '../router.js';
17:import { getApi, getBreadcrumb, getStatus, rerender } from './context.js';
18:
19:/* -------------------------------------------------------------------------
20: * Row action menu open/close state
21: *
22: * At most one row menu (the "⋮" dropdown OR a right-click context menu) is
23: * open at a time. `openRowMenu` holds the close function of whichever menu is
24: * currently showing, so `closeAllRowMenus()` can dismiss it before opening
25: * another and — crucially — so the menu's document-level click / Escape
26: * listeners are removed on close rather than leaking across renders or rapid
27: * open/close cycles. Module-scoped (not per-row) because the "only one menu
28: * open" invariant spans every row in the table.
29: * ---------------------------------------------------------------------- */
30:let openRowMenu: { close: () => void } | null = null;
31:
32:/** Close whichever row menu (if any) is currently open. Idempotent no-op when none is open. */
33:function closeAllRowMenus(): void {
34:  openRowMenu?.close();
35:  openRowMenu = null;
36:}
