38:/**
39: * Build a `<table>` with a `<thead>` (one `<th>` per header label) and an empty
40: * `<tbody>`. The caller appends rows to the `<tbody>`.
41: */
42:export function buildTable(headers: string[]): HTMLTableElement {
43:  const table = document.createElement('table');
44:  table.className = 'results-table';
45:  const thead = document.createElement('thead');
46:  const headRow = document.createElement('tr');
47:  for (const label of headers) {
48:    const th = document.createElement('th');
49:    th.textContent = label;
50:    headRow.append(th);
51:  }
52:  thead.append(headRow);
53:  const tbody = document.createElement('tbody');
54:  table.append(thead, tbody);
55:  return table;
56:}
