58:/**
59: * Render clickable breadcrumb segments into the shared breadcrumb element: a
60: * leading "Home" link (root) followed by one link per path segment, each
61: * navigating to its cumulative path. Separators are plain '/' text spans.
62: */
63:export function renderBreadcrumb(path: string): void {
64:  const breadcrumbEl = getBreadcrumb();
65:  breadcrumbEl.innerHTML = '';
66:  const normalized = normalizeRelativePath(path);
67:  const segments = normalized === '' ? [] : normalized.split('/');
68:
69:  breadcrumbEl.append(makeNavLink('Home', toBrowseHash('')));
70:
71:  let cumulative = '';
72:  for (const segment of segments) {
73:    cumulative = joinPath(cumulative, segment);
74:    const separator = document.createElement('span');
75:    separator.textContent = '/';
76:    breadcrumbEl.append(separator, makeNavLink(segment, toBrowseHash(cumulative)));
77:  }
78:}
