80:/**
81: * Build an `<a>` that navigates to `hash` on click. The `href` is set via
82: * `setAttribute` (so the raw attribute is preserved exactly — important for
83: * download URLs that must not be URL-normalized) and a click handler calls
84: * `navigate(hash)` with `preventDefault` so navigation is reliable across DOM
85: * implementations. The href also enables middle-click / copy-link support.
86: */
87:export function makeNavLink(text: string, hash: string): HTMLAnchorElement {
88:  const link = document.createElement('a');
89:  link.setAttribute('href', hash);
90:  link.textContent = text;
91:  link.addEventListener('click', (event) => {
92:    event.preventDefault();
93:    navigate(hash);
94:  });
95:  return link;
96:}
