99:export function makeParentRow(parent: string): HTMLTableRowElement {
100:  const row = document.createElement('tr');
101:  const nameCell = document.createElement('td');
102:  nameCell.append(makeNavLink('..', toBrowseHash(parent)));
103:  const sizeCell = document.createElement('td');
104:  const modifiedCell = document.createElement('td');
105:  const actionsCell = document.createElement('td');
106:  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
107:  return row;
108:}
