110:/**
111: * Build the per-row "⋮" action menu for a browse data row: a `.row-menu-btn`
112: * (the three-dots trigger) and its `.row-menu` dropdown of action items
113: * (Download for files only, then Delete / Move / Copy). Returns both elements
114: * plus the row-local `openMenu(x, y)` so `makeBrowseRow` can also open the
115: * SAME menu on a right-click anywhere on the row.
116: *
117: * Open / close lifecycle:
118: *  - The button toggles: when closed, `stopPropagation()` on the opening
119: *    click (so it never reaches the just-registered document listener) then
120: *    `openMenu` below the button via `getBoundingClientRect()`; when open, a
121: *    second click closes it.
122: *  - `openMenu` first calls `closeAllRowMenus()` (only one open at a time),
123: *    positions the `position: fixed` menu at viewport `(x, y)` px, reveals it,
124: *    flips `aria-expanded` to `'true'`, registers one-shot document `click`
125: *    (close on the next click anywhere — outside OR on a menu item, after the
126: *    item's own handler has run) and `keydown` (close on Escape) listeners,
127: *    and records itself as the open menu.
128: *  - `closeMenu` hides the menu, restores `aria-expanded` to `'false'`, removes
129: *    both document listeners, and clears `openRowMenu` if it still points here.
130: *
131: * The action-item handler bodies are identical to the former inline buttons
132: * (same `window.confirm` / `prompt`, `getApi().delete/move/copy`,
133: * `normalizeRelativePath`, and `rerender()` calls) so all behavior is
134: * preserved. The items keep `class="btn"` (the `.row-menu .btn` CSS restyles
135: * them into menu items) so existing query/characterization assertions hold.
136: */
137:function makeRowMenu(entry: FileEntry): {
138:  btn: HTMLButtonElement;
139:  menu: HTMLElement;
140:  openMenu: (x: number, y: number) => void;
141:} {
142:  const btn = document.createElement('button');
143:  btn.className = 'row-menu-btn';
144:  btn.type = 'button';
145:  btn.setAttribute('aria-label', 'Actions');
146:  btn.setAttribute('aria-haspopup', 'true');
147:  btn.setAttribute('aria-expanded', 'false');
148:  btn.textContent = '⋮';
149:
150:  const menu = document.createElement('div');
151:  menu.className = 'row-menu';
152:  menu.hidden = true;
153:
154:  // Menu items — same handlers/attributes as the former inline controls.
155:  if (!entry.isDirectory) {
156:    const download = document.createElement('a');
157:    download.className = 'btn';
158:    download.setAttribute('href', getApi().downloadUrl(entry.path));
159:    download.setAttribute('download', entry.name);
160:    download.textContent = 'Download';
161:    menu.append(download);
162:  }
163:  menu.append(
164:    makeActionButton('Delete', async () => {
165:      if (!window.confirm('Delete "' + entry.name + '"?')) {
166:        return;
167:      }
168:      await getApi().delete(entry.path);
169:      rerender();
170:    }),
171:  );
172:  menu.append(
173:    makeActionButton('Move', async () => {
174:      const dest = window.prompt('Move to relative destination path:', entry.path);
175:      if (dest === null) {
176:        return;
177:      }
178:      await getApi().move(entry.path, normalizeRelativePath(dest));
179:      rerender();
180:    }),
181:  );
182:  menu.append(
183:    makeActionButton('Copy', async () => {
184:      const dest = window.prompt('Copy to relative destination path:', entry.path);
185:      if (dest === null) {
186:        return;
187:      }
188:      await getApi().copy(entry.path, normalizeRelativePath(dest));
189:      rerender();
190:    }),
191:  );
192:
193:  // Document listeners registered on open, removed on close. Kept as named
194:  // references so removeEventListener tears down the exact functions.
195:  function onDocClick(): void {
196:    closeMenu();
197:  }
198:  function onDocKey(event: KeyboardEvent): void {
199:    if (event.key === 'Escape') {
200:      closeMenu();
201:    }
202:  }
203:
204:  function closeMenu(): void {
205:    menu.hidden = true;
206:    btn.setAttribute('aria-expanded', 'false');
207:    document.removeEventListener('click', onDocClick);
208:    document.removeEventListener('keydown', onDocKey);
209:    if (openRowMenu?.close === closeMenu) {
210:      openRowMenu = null;
211:    }
212:  }
213:
214:  function openMenu(x: number, y: number): void {
215:    closeAllRowMenus();
216:    menu.style.left = x + 'px';
217:    menu.style.top = y + 'px';
218:    menu.hidden = false;
219:    btn.setAttribute('aria-expanded', 'true');
220:    document.addEventListener('click', onDocClick);
221:    document.addEventListener('keydown', onDocKey);
222:    openRowMenu = { close: closeMenu };
223:  }
224:
225:  // Toggle: open below the button, or close if already open. stopPropagation on
226:  // the OPENING click is critical — without it the click would bubble to the
227:  // document listener registered by openMenu and close the menu immediately.
228:  btn.addEventListener('click', (event) => {
229:    if (menu.hidden) {
230:      event.stopPropagation();
231:      const rect = btn.getBoundingClientRect();
232:      openMenu(rect.left, rect.bottom);
233:    } else {
234:      closeMenu();
235:    }
236:  });
237:
238:  return { btn, menu, openMenu };
239:}
