241:/** One data row in the browse table (a file or folder entry). */
242:export function makeBrowseRow(entry: FileEntry): HTMLTableRowElement {
243:  const row = document.createElement('tr');
244:
245:  // Name — directory names are navigation links; file names are plain text.
246:  const nameCell = document.createElement('td');
247:  if (entry.isDirectory) {
248:    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
249:  } else {
250:    nameCell.textContent = entry.name;
251:  }
252:
253:  // Size — em-dash for folders, formatted bytes for files.
254:  const sizeCell = document.createElement('td');
255:  sizeCell.textContent = entry.isDirectory ? '—' : formatBytes(entry.size);
256:
257:  // Modified
258:  const modifiedCell = document.createElement('td');
259:  modifiedCell.textContent = formatDate(entry.lastModified);
260:
261:  // Actions — a "⋮" dropdown button + its menu (also opened by right-clicking
262:  // anywhere on the row, positioned at the cursor). The action items and their
263:  // handlers are built by makeRowMenu; see its doc comment for the open/close
264:  // contract.
265:  const actionsCell = document.createElement('td');
266:  const { btn, menu, openMenu } = makeRowMenu(entry);
267:  actionsCell.append(btn, menu);
268:  row.addEventListener('contextmenu', (event) => {
269:    event.preventDefault();
270:    openMenu(event.clientX, event.clientY);
271:  });
272:
273:  row.append(nameCell, sizeCell, modifiedCell, actionsCell);
274:  return row;
275:}
