277:/**
278: * Build a `<button class="btn">` with the given label and click handler.
279: *
280: * The handler is wrapped so that any synchronous throw or promise rejection
281: * surfaces the error via the status footer — consistent with how `render()`
282: * already displays fetch errors. On normal resolution no error message is
283: * shown.
284: */
285:export function makeActionButton(label: string, handler: () => void): HTMLButtonElement {
286:  const btn = document.createElement('button');
287:  btn.className = 'btn';
288:  btn.type = 'button';
289:  btn.textContent = label;
290:  btn.addEventListener('click', () => {
291:    try {
292:      Promise.resolve(handler()).catch((err: unknown) => {
293:        getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
294:      });
295:    } catch (err) {
296:      getStatus().textContent = 'Error: ' + (err instanceof Error ? err.message : String(err));
297:    }
298:  });
299:  return btn;
300:}
