302:/** One data row in the search-results table. */
303:export function makeSearchRow(entry: FileEntry): HTMLTableRowElement {
304:  const row = document.createElement('tr');
305:
306:  // Name — directories browse into; files open their download URL.
307:  const nameCell = document.createElement('td');
308:  if (entry.isDirectory) {
309:    nameCell.append(makeNavLink(entry.name, toBrowseHash(entry.path)));
310:  } else {
311:    const link = document.createElement('a');
312:    link.setAttribute('href', getApi().downloadUrl(entry.path));
313:    link.textContent = entry.name;
314:    nameCell.append(link);
315:  }
316:
317:  // Path
318:  const pathCell = document.createElement('td');
319:  pathCell.textContent = entry.path;
320:
321:  // Size
322:  const sizeCell = document.createElement('td');
323:  sizeCell.textContent = formatBytes(entry.size);
324:
325:  // Modified
326:  const modifiedCell = document.createElement('td');
327:  modifiedCell.textContent = formatDate(entry.lastModified);
328:
329:  row.append(nameCell, pathCell, sizeCell, modifiedCell);
330:  return row;
331:}

